const raw = $input.first().json.candidates[0].content.parts[0].text;
const clean = raw.trim().replace(/^```json/i, '').replace(/^```/, '').replace(/```$/, '').trim();
const script = JSON.parse(clean);
let sources = [];
try {
  const gm = $('Research').first().json.candidates[0].groundingMetadata;
  const chunks = (gm && gm.groundingChunks) || [];
  sources = chunks.map(c => c.web && c.web.uri).filter(Boolean);
} catch (e) {}
script.sources = sources;
return [{ json: script }];
